using Color = Microsoft.Xna.Framework.Color;

namespace TerraAngel.WorldEdits;

public readonly struct TileColor
{
    public readonly int Type;
    public readonly int Paint;
    public readonly Color Color;
    public readonly double LabL;
    public readonly double LabA;
    public readonly double LabB;

    public TileColor(int type, int paint, Color color, double labL, double labA, double labB)
    {
        Type = type;
        Paint = paint;
        Color = color;
        LabL = labL;
        LabA = labA;
        LabB = labB;
    }

    public double[] GetLab() => new[] { LabL, LabA, LabB };
}

